package com.cognizant.ems.model; import java.time.*; import jakarta.persistence.*; import org.springframework.data.annotation.*; import org.springframework.data.jpa.domain.support.*;
@Entity @EntityListeners(AuditingEntityListener.class) @NamedQuery(name="Employee.byEmail",query="select e from Employee e where e.email=:email") public class Employee {@Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id;private String name;@Column(unique=true)private String email;private double salary;@ManyToOne(fetch=FetchType.LAZY)@JoinColumn(name="department_id")private Department department;@CreatedDate private Instant createdAt;@LastModifiedDate private Instant updatedAt; public Long getId(){return id;}public String getName(){return name;}public void setName(String v){name=v;}public String getEmail(){return email;}public void setEmail(String v){email=v;}public double getSalary(){return salary;}public void setSalary(double v){salary=v;}public Department getDepartment(){return department;}public void setDepartment(Department v){department=v;}}
